args.sparql:
SELECT (MIN(YEAR(?eventDate)) AS ?firstYear)
WHERE {
  ?event wdt:P31 wd:Q248297 .
  {
    ?event wdt:P93 wd:Q249679 ;
           wdt:P2513 ?opponentTeam .
  }
  UNION
  {
    ?event wdt:P2513 wd:Q249679 ;
           wdt:P93 ?opponentTeam .
  }
  FILTER(?opponentTeam != wd:Q249679)
  ?event wdt:P585 ?eventDate .
}
GROUP BY ?opponentTeam
ORDER BY MIN(YEAR(?eventDate))
OFFSET 3
LIMIT 1

